// Parse & extract structured data from Booking Agent output
const agentOutput = $input.first().json.output ?? $input.first().json.text ?? '';

// ─── Helpers ───────────────────────────────────────────────────────────────
function extract(pattern, text, group = 1) {
  const m = text.match(pattern);
  return m ? m[group].trim() : null;
}

// ─── Extract fields ─────────────────────────────────────────────────────────
const dateMatch   = extract(/\b(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}|(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\.?\s+\d{1,2},?\s*\d{4}|\d{4}-\d{2}-\d{2})/i, agentOutput);
const timeMatch   = extract(/\b(\d{1,2}:\d{2}(?::\d{2})?\s*(?:AM|PM|am|pm)?)/i, agentOutput);
const serviceMatch= extract(/(?:service|appointment|event|booking)[:\s]+([^,\.\n]+)/i, agentOutput);
const statusMatch = extract(/(confirmed|scheduled|booked|cancelled|rescheduled|pending)/i, agentOutput, 0);
const nameMatch   = extract(/(?:for|client|patient|name)[:\s]+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)/i, agentOutput);
const idMatch     = extract(/(?:ID|id|#|confirmation)[:\s#]+(\w{4,})/i, agentOutput);

// ─── Build structured result ─────────────────────────────────────────────────
const parsed = {
  raw:          agentOutput,
  status:       statusMatch ?? 'unknown',
  date:         dateMatch   ?? null,
  time:         timeMatch   ?? null,
  service:      serviceMatch?? null,
  clientName:   nameMatch   ?? null,
  confirmationId: idMatch   ?? null,
  parsedAt:     new Date().toISOString(),
};

// ─── Build a clean summary for the WhatsApp reply ────────────────────────────
const lines = [];
if (parsed.status !== 'unknown') lines.push(`Status: ${parsed.status.toUpperCase()}`);
if (parsed.service)              lines.push(`Service: ${parsed.service}`);
if (parsed.date)                 lines.push(`Date: ${parsed.date}`);
if (parsed.time)                 lines.push(`Time: ${parsed.time}`);
if (parsed.clientName)           lines.push(`Client: ${parsed.clientName}`);
if (parsed.confirmationId)       lines.push(`Ref: ${parsed.confirmationId}`);

parsed.summary = lines.length > 0
  ? lines.join('\n')
  : agentOutput; // fallback to raw if nothing parsed

return [{ json: parsed }];
